cd /c/repos/shared-db
perl -0777 -pe '
# 1) add declares after core_company_id uuid;
s/(
  core_company_id uuid;
)/$1  v_match_id uuid;
  v_review_id uuid;
  v_review_sim real;
  v_erp_domain text;
/;

# 2) replace exact-name match block with fuzzy resolver call
my $old = qq{    if core_company_id is null then
      select c.id
      into core_company_id
      from core.customer c
      where c.company_type = '"'"'customer'"'"'
        and c.normalized_name = lower(regexp_replace(v_source_name, '"'"'\\s+'"'"', '"'"' '"'"', '"'"'g'"'"'))
      order by c.created_at
      limit 1;
    end if;
};
my $new = qq{    -- Fuzzy entity resolution: exact name -> exact domain -> high-similarity name.
    -- A mid-band similarity is NOT auto-merged; it is flagged for human review.
    if core_company_id is null then
      v_erp_domain := lower(split_part(nullif(customer_row ->> '"'"'customers_email'"'"', '"'"''"'"'), '"'"'\@'"'"', 2));
      select m.match_id, m.review_id, m.review_sim
        into v_match_id, v_review_id, v_review_sim
      from core.match_customer(v_source_name, v_erp_domain) m;
      core_company_id := v_match_id;
    end if;
};
my $i = index($_, $old);
if ($i < 0) { print STDERR "TRANSFORM2 NO MATCH
"; } else { substr($_, $i, length($old)) = $new; }
' /tmp/plm_import_recreated.sql > /tmp/plm_step2.sql

# 3) insert dedupe-candidate write before the plm.customer_import insert
perl -0777 -pe '
my $anchor = qq{    insert into plm.customer_import (
};
my $block = qq{    if v_review_id is not null then
      insert into ingest.dedupe_candidate (
        entity_schema, entity_table, left_entity_id, right_entity_id,
        source_system, confidence, reason, raw
      )
      values (
        '"'"'core'"'"', '"'"'customer'"'"', core_company_id, v_review_id,
        '"'"'designflow_plm'"'"', '"'"'possible'"'"',
        format('"'"'Fuzzy name match %s between ERP customer "%s" and an existing potential customer; review for merge.'"'"', round(v_review_sim::numeric, 2), v_source_name),
        jsonb_build_object('"'"'erp_customer_id'"'"', v_source_id, '"'"'erp_name'"'"', v_source_name, '"'"'similarity'"'"', v_review_sim)
      );
    end if;

};
my $i = index($_, $anchor);
if ($i < 0) { print STDERR "TRANSFORM3 NO MATCH
"; } else { substr($_, $i, 0) = $block; }
' /tmp/plm_step2.sql > /tmp/plm_import_fuzzy.sql

echo "=== sanity ==="
grep -c "core.match_customer" /tmp/plm_import_fuzzy.sql
grep -c "ingest.dedupe_candidate" /tmp/plm_import_fuzzy.sql
grep -c "v_erp_domain text;" /tmp/plm_import_fuzzy.sql
awk 'BEGIN{a=0}{a+=gsub(/\$\$/,"$$")}END{printf "  $$ markers: %d %s
", a,(a%2?"ODD!":"ok")}' /tmp/plm_import_fuzzy.sql
wc -l /tmp/plm_import_fuzzy.sql

